+export function resolveMusicGenerationModelConfigForTool(params: {
+  cfg?: OpenClawConfig;
+  agentDir?: string;
+}): ToolModelConfig | null {
+  return resolveCapabilityModelConfigForTool({
+    cfg: params.cfg,
